import type { ProductCardProps } from "../../utils/propsUtils";
import { receiptFontBold, receiptFontSemibold } from "../../utils/stylingUtils";

export default function ProductCard({ product, quantity, onClick }: ProductCardProps) {
    const handleKeyDown = (e: React.KeyboardEvent) => {
        if ((e.key === "Enter" || e.key === " ") && onClick) {
            e.preventDefault();
            onClick();
        }
    };

    return (
        <div
            role="button"
            tabIndex={0}
            onClick={onClick}
            onKeyDown={handleKeyDown}
            className="flex items-center justify-between px-4 py-3 bg-gray-700 rounded border border-green-400 hover:shadow-lg hover:shadow-green-400/50 hover:bg-gray-600 cursor-pointer transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-green-400"
            aria-label={`View details for ${product.name}`}
        >
            <div className="flex-1">
                <h5 className={receiptFontSemibold}>{product.name}</h5>
                <p className="text-xs text-gray-400">ID: {product.id}</p>
            </div>
            <div className="text-right">
                <p className={receiptFontBold}>Quantity: {quantity ?? "N/A"}</p>
                <p className="text-xs text-gray-400">
                    Expiry: {new Date(product["expiry-date"]).toLocaleDateString()}
                </p>
            </div>
        </div>
    );
}
